    key?: string;
    /**
     * Label to display on the button.
     */
    label?: string;
    /**
     * Icon to display on the button.
     */
    icon?: string;
    /**
     * Determines with what entries the asset library is opened.
     */
    entries: string[];
    /**
     * Custom onClick handler. If provided, overrides the default asset library toggle behavior.
     */
    onClick?: () => void;
    /**
     * Controls the selected state of the button. If provided, overrides the automatic detection.
     * Can be a boolean or a function that returns a boolean for reactive updates.
     */
