/**
 * @public
 * Interface representing the data configuration for an asset library entry.
 * - `id`: The unique identifier for the asset library entry.
 * - `sourceIds`: An array of source IDs associated with the asset library entry, or a function that returns an array of source IDs.
 * - `sceneMode`: @deprecated Since v1.72. Optional configuration for the scene mode. Not needed for new scenes.
 * - `excludeGroups`: Optional array of group IDs to exclude from the asset library entry.
 * - `includeGroups`: Optional array of group IDs to include in the asset library entry.
 * - `title`: Optional title for the asset library entry, which can be a string or a function returning a string or undefined.
 * - `canAdd`: Optional boolean or function indicating whether the asset can be added to the source.
 * - `canRemove`: Optional boolean or function indicating whether the asset can be removed from the source.
 */
declare interface AssetLibraryEntryData {
    id: string;
    sourceIds: string[] | ((context: AssetEntrySourceIdsContext) => string[]);
    /**
     * @deprecated Since v1.72. Scene mode no longer affects engine behavior.
     * Not setting this will make the entry available for all scenes.
     */
    sceneMode?: SceneMode | 'All' | ((context: {
        sourceId: string;
    }) => SceneMode | 'All');
    excludeGroups?: string[];
    includeGroups?: string[];
    title?: string | ((options: {
        group?: string;
        sourceId?: string;
    }) => string | undefined);
    /**
     * If `true` an upload button will be shown and the uploaded file will be
     * added to the source.
     *
     * If a function is used it will be called with the current asset source id.
     *
     * The asset source needs to support `addAsset`.
     */
    canAdd?: boolean | ((sourceId: string) => boolean);
    /**
     * If `true` the asset can be removed from the asset source.
     *
     * If a function is used it will be called with the current asset source id.
     *
     * The asset source needs to support `removeAsset`.
     */
    canRemove?: boolean | ((sourceId: string) => boolean);
}

/**
 * @public
 * Interface representing the view configuration for an asset library entry.
 * - `showGroupOverview`: Optional boolean indicating whether to show the group overview.
 * - `promptBeforeApply`: Optional configuration for showing a confirmation dialog before applying an asset.
 * - `icon`: Optional custom icon for the asset.
 * - `previewLength`: Optional number determining how many asset results will be shown in an overview or section overview.
 * - `previewBackgroundType`: Optional type determining if the thumbUri is set as a background that will be contained or covered by the card in an overview or section overview.
 * - `gridBackgroundType`: Optional type determining if the thumbUri is set as a background that will be contained or covered by the card in the grid view.
 * - `gridColumns`: Optional number of columns in the grid view.
 * - `gridItemHeight`: Optional height of an item in the grid view, either 'auto' or 'square'.
 * - `cardBackgroundPreferences`: Optional configuration for determining what will be used as the card background from the asset and in which priorities.
 * - `cardBorder`: Optional boolean indicating whether to draw a border around the card.
 * - `cardLabel`: Optional function to overwrite the label of a card for a specific asset result.
 * - `cardStyle`: Optional function to add custom styles to a card for a specific asset result.
 * - `cardLabelStyle`: Optional function to add custom styles to a label for a specific asset result.
 * - `cardLabelPosition`: Optional function to position the label inside or below the card.
 * - `cardLabelTruncateLines`: Optional function to control label truncation to occur at end of first line ('single') or at end of second line ('multi').
 * - `sortBy`: Optional configuration for sorting the asset results.
 */
declare interface AssetLibraryEntryView {
    showGroupOverview?: boolean;
    /**
     * Indicates whether this asset library entry supports searching.
     * When set to false, this entry's assets cannot be searched.
     * The search field in the panel will only be shown if at least one visible entry is searchable.
     * Defaults to true (entry is searchable).
     */
    isSearchable?: boolean;
    /**
     * Wether or not we need to show a confirmation dialog when an asset is selected.
     *
     * accepted values:
     * - `true`: Show a confirmation dialog for all assets
     * - `false`: Never show a confirmation dialog
     * - `{ show: true, sourceIds: ['sourceId1', 'sourceId2'] }`: Show a confirmation dialog for the given sourceIds
     *
     * The content of the dialog should be defined in the translation files using the following keys:
     * - Headline: `libraries.[your_source_id].confirmation.headline`
     * - Body: `libraries.[your_source_id].confirmation.body`
     * - Confirm: `libraries.[your_source_id].confirmation.confirm`
     * - Abort: `libraries.[your_source_id].confirmation.abort`
     */
    promptBeforeApply?: boolean | {
        show: boolean;
        sourceIds?: string[];
    };
    icon?: CustomIcon;
    /**
     * Determines how many asset results will be show in an overview or
     * section overview.
     */
    previewLength?: number;
    /**
     * Determines if the thumbUri is set as a background that will be
     * contained or covered by the card in an overview or section overview.
     */
    previewBackgroundType?: 'cover' | 'contain';
    /**
     * Determines if the thumbUri is set as a background that will be
     * contained or covered by the card in the grid view
     */
    gridBackgroundType?: 'cover' | 'contain';
    /**
     * Number of columns in the grid view
     */
    gridColumns?: number;
    /**
     * Determines the height of an item in the grid view.
     *
     * - `auto` automatically determine height yielding a masonry-like grid view
     * - `square` every card will have the same square size
     */
    gridItemHeight?: 'auto' | 'square';
    /**
     * Determines what will be used as the card background from the asset and in
     * which priorities.
     *
     * The first preference for which the `path` returns a value will be used to
     * decide what and how the background will be rendered.
     *
     * E.g. a path of `meta.thumbUri` will look inside the asset for a value
     * `asset.meta.thumbUri`. This non-null value will be used.
     *
     * The type of the preference decides how the card will render the background.
     *
     * - `svgVectorPath` - creates a <svg> element with the given vector path.
     *                     Adapts the color depending on the theme
     * - `image` - use a CSS background image
     *
     * Example of the default:
     *
     * ```
     * [
     *  { path: 'meta.vectorPath', type: 'svgVectorPath' },
     *  { path: 'meta.thumbUri', type: 'image' }
     * ]
     * ```
     *
     * This will look if the asset has a value in `meta.vectorPath` and will use
     * this value to render a SVG as background. If `meta.vectorPath` has no
     * value, it will use `meta.thumbUri` instead as a background image.
     * Otherwise it will render nothing
     */
    cardBackgroundPreferences?: CardBackground[] | ((asset: AssetResult) => CustomCardBackground);
    /**
     * Draws a border around the card if set to true
     */
    cardBorder?: boolean;
    /**
     * Overwrite the label of a card for a specific asset result
     */
    cardLabel?: (assetResult: AssetResult) => string | undefined;
    /**
     * Add custom styles to a card for a specific asset result
     */
    cardStyle?: (assetResult: AssetResult) => Record<string, string | undefined>;
    /**
     * Add custom styles to a label for a specific asset result
     */
    cardLabelStyle?: (assetResult: AssetResult) => Record<string, string | undefined>;
    /**
     * Position the label inside or below the card.
     * Defaults to 'inside'.
     */
    cardLabelPosition?: (assetResult: AssetResult) => 'inside' | 'below';
    /**
     * Control label truncation to occur at end of first line ('single'), or at end of second line ('multi').
     * Defaults to 'multi'.
     */
    cardLabelTruncateLines?: (assetResult: AssetResult) => 'single' | 'multi';
    /**
     * Control whether tooltips should be disabled for asset library cards.
     * When set to true, tooltips will not be shown on cards.
     * Defaults to false (tooltips are shown).
     */
    disableTooltips?: boolean;
    sortBy?: SortingOrder | {
        sortKey?: string;
        sortingOrder?: SortingOrder;
    } | {
        sourceId: string;
        sortKey?: string;
        sortingOrder?: SortingOrder;
    }[];
}

